#!/usr/bin/env python3
"""
MKT Christ — Habakkuk all 3 chapters (56 verses)
Run: python3 scripts/zc-christ-habakkuk-1-3-full.py

Key Christological connections:
- 1:5 work you would not believe → Acts 13:41 (Paul quotes directly in synagogue)
- 2:4 the righteous shall live by his faith → Rom 1:17; Gal 3:11; Heb 10:38
- 2:14 earth filled with knowledge of YHWH's glory → Rev 21:23; Eph 1:10
- 2:20 YHWH in his holy temple → Rev 8:1; Heb 4:16 (access through Christ)
- 3:2 revive your work → John 12:28; 2 Cor 4:14 (resurrection/renewing)
- 3:13 you went out for salvation of your people → Titus 2:14; 1 Pet 2:9
- 3:17-18 though fig tree does not blossom → Phil 4:11-13; 1 Tim 6:6 (contentment in Christ)
- 3:19 YHWH is my strength, makes feet like deer → Phil 4:13; Eph 6:10
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HABAKKUK = {
    "1": {
        "1": '<p class="christ-theme">The burden (<em>massa</em>) Habakkuk the prophet saw opens with the same designation as Nahum (also <em>massa</em>) and points forward to the apostolic designation of the gospel as a proclamation-under-authority. The word <em>massa</em> carries the double sense of burden and oracle — the prophet carries the weight of what he must speak. Paul\'s preaching is similarly driven: "Woe to me if I do not preach the gospel!" (1 Cor 9:16). The burden the prophet receives becomes in Christ the message entrusted to those who have been given the ministry of reconciliation (2 Cor 5:18-19).</p>',
        "2": '<p class="christ-theme">The prophet\'s cry — "How long, O YHWH, will I cry for help and you will not hear?" — is the OT\'s raw lament form that Christ himself inhabits from the cross: "My God, my God, why have you forsaken me?" (Matt 27:46, citing Ps 22:1). The prophet\'s unanswered cry becomes the forsaken cry of the Son on the cross — the moment when the Father\'s apparent silence reaches its nadir. But as Psalm 22 moves from desolation to vindication, so Christ\'s death moves to resurrection. The cry of Habakkuk 1:2 is answered not by immediate rescue but by the resurrection that answers all such cries definitively.</p>',
        "3": '<p class="christ-theme">Violence (<em>chamas</em>) and strife confronting Habakkuk — the law paralyzed, justice perverted — describe the world\'s condition that the gospel addresses. James echoes the same diagnosis: "You desire and do not have, so you murder. You covet and cannot obtain, so you fight and quarrel" (Jas 4:2). The social disorder Habakkuk laments as evidence of YHWH\'s apparent inaction is the world into which Christ comes to make peace through the blood of his cross (Col 1:20), reconciling not just individuals but the disordered structure of human community.</p>',
        "4": '<p class="christ-theme">The law being paralyzed and justice going forth perverted — the breakdown of the covenant order — is precisely the situation Christ diagnoses in the Pharisees\' handling of Scripture: "You have let go of the commands of God and are holding on to human traditions" (Mark 7:8). He comes not to abolish but to fulfill the law (Matt 5:17), restoring it from perversion to its original glory. What Habakkuk mourns as the collapse of the covenant structure, Christ rectifies in his own person — he is the end of the law for righteousness to everyone who believes (Rom 10:4).</p>',
        "5": '<p class="christ-direct">YHWH\'s response: "Look among the nations and watch — be utterly astounded! For I will do something in your days that you would not believe even if told." Paul cites this verse directly in his synagogue sermon at Antioch (Acts 13:40-41): "Beware, therefore, lest what is said in the Prophets should come about: \'Look, you scoffers, be astounded and perish; for I am doing a work in your days, a work that you will not believe, even if one tells it to you.\'" The work YHWH announces to Habakkuk is the Babylonian invasion; Paul applies the same rhetorical structure to the resurrection of Christ — the work no one would have believed, the stone the builders rejected, the foolishness that is the wisdom of God (1 Cor 1:23-24).</p>',
        "6": '<p class="christ-theme">The Chaldeans raised up as YHWH\'s instrument — "that bitter and hasty nation" marching through the breadth of the earth — illustrates the divine use of human powers for redemptive purposes. Paul makes the same logic explicit: rulers are YHWH\'s servants even when they do not know it (Rom 13:4). More specifically, the "bitter and hasty" characteristics of unbelieving empire echo in Jesus\'s teaching about the coming judgment — "There will be great tribulation" — as the mechanism by which divine purposes advance in history (Matt 24:21). The nations are instruments in YHWH\'s hand; Christ is the one who holds history\'s purpose.</p>',
        "7": '<p class="christ-theme">The Chaldeans being "dreaded and fearsome" — their own justice and dignity proceeding from themselves — is the profile of the self-referential power that Christ unmasks and defeats. When Pilate says "Do you not know that I have authority to release you and authority to crucify you?", Jesus answers: "You would have no authority over me at all unless it had been given you from above" (John 19:10-11). The power that proceeds from itself is exposed as derived power; only in Christ is authentic authority located — "all authority in heaven and on earth has been given to me" (Matt 28:18).</p>',
        "8": '<p class="christ-allusion">The swifter-than-leopards, fiercer-than-evening-wolves imagery for the Chaldean cavalry — horses flying like eagles — describes human military power at its most formidable. This is the imperial spectacle before which human resistance is futile. The book of Revelation uses the same imagery to depict the powers that will face the rider on the white horse (Rev 19:11-16) — and are defeated. The armies that terrified Habakkuk\'s world are, in the Apocalypse, nothing before the one whose name is the Word of God.</p>',
        "9": '<p class="christ-theme">The Chaldeans coming for violence, gathering captives "as sand" — their faces pressing forward — describes the gathering of the nations against YHWH\'s people. This is the pressure that Revelation describes as the gathering of the nations for war before the final judgment (Rev 16:14). Between Habakkuk\'s historical Babylon and Revelation\'s eschatological Babylon stands Christ\'s cross — the turning point at which the gathering of the nations for violence became the ground of their possible redemption (John 12:32, "I will draw all people to myself").</p>',
        "10": '<p class="christ-theme">The Chaldeans scoffing at kings, heaping ridicule on rulers, laughing at every fortress — the arrogant dismissal of all human pretension to power — anticipates the laughter of the one who sits in the heavens at the nations\' rage (Ps 2:4). Christ is the one before whom all such scoffing is ultimately directed and ultimately reversed: those who mocked at the cross — "He saved others; let him save himself" (Luke 23:35) — find in the resurrection the answer to all human scoffing at divine power.</p>',
        "11": '<p class="christ-allusion">The sweeping of the Chaldeans through the world — "then they sweep past like the wind and go on, guilty men, whose own might is their god" — describes the idolatry of power: military strength deified. Paul identifies this as the fundamental form of human sin: exchanging the Creator for the creature, worshipping and serving created things rather than the Creator (Rom 1:25). Christ reverses the deification of power by embodying the power made perfect in weakness (2 Cor 12:9) — the kingdom that comes not through military sweep but through suffering love.</p>',
        "12": '<p class="christ-theme">Habakkuk\'s second complaint — "Are you not from everlasting, O YHWH my God, my Holy One? We shall not die" — is an act of faith within lament. The confidence "we shall not die" is the covenant counterweight to the horror of the Chaldean advance. It reaches its NT form in Paul\'s declaration: "For I am sure that neither death nor life... will be able to separate us from the love of God in Christ Jesus our Lord" (Rom 8:38-39). Habakkuk\'s covenant confidence that YHWH\'s everlasting nature protects his people is grounded, for Paul, in the resurrection of the one who is the same yesterday, today, and forever (Heb 13:8).</p>',
        "13": '<p class="christ-theme">YHWH\'s eyes being too pure to look at evil — "you cannot look at wrong" — establishes the divine holiness that makes the cross necessary. God cannot simply overlook sin while remaining just; atonement is required. Paul articulates the logic: "God presented Christ as a propitiation through faith in his blood... to demonstrate his righteousness at the present time, so as to be just and the one who justifies those who have faith in Jesus" (Rom 3:25-26). The God too pure to look at evil provides the one who bears that evil so that YHWH can be both holy and the justifier of the ungodly.</p>',
        "14": '<p class="christ-theme">The fish metaphor — humanity treated like fish with no ruler, caught in a net, swept away — describes the human condition as one of helpless capture. Jesus transforms the metaphor: calling fishermen to become fishers of people (Matt 4:19), using the same domain imagery to describe the gathering of the kingdom (Matt 13:47-50). Where the Chaldean empire uses the net to capture for destruction, Christ uses it to gather for salvation. The reversal is complete: those swept away in judgment become the gathered community of the new covenant.</p>',
        "15": '<p class="christ-allusion">The Chaldeans rejoicing and exulting while sacrificing to their net — treating their military equipment as divine — is the OT form of what Paul calls the wisdom of the world: "the world did not know God through wisdom" (1 Cor 1:21). The worshipped net, like Greek wisdom and Jewish signs, is the human substitute for the true God. Christ\'s cross is the wisdom of God that makes all substitute wisdoms foolish — "the foolishness of God is wiser than men, and the weakness of God is stronger than men" (1 Cor 1:25).</p>',
        "16": '<p class="christ-theme">The sacrificing to the net and making offerings to the drag-net continuing as long as the catch is fat describes the cycle of imperial self-worship — success interpreted as divine favor, power perpetuating its own religious system. This is the spiritual structure of every human empire. Christ\'s kingdom breaks the cycle: the poor and weak are included (Luke 6:20-22), the powerful are brought down (Luke 1:52), and the net of the kingdom catches every kind (Matt 13:47). No tribute to the equipment; glory to the one who governs all.</p>',
        "17": '<p class="christ-theme">The chapter\'s closing question — "Is he then to keep on emptying his net and mercilessly killing nations forever?" — is the unanswered question that drives the book forward. It is the existential pressure behind Habakkuk\'s prophetic waiting. Revelation answers it: the nations\' destroying will be ended when "the time came for destroying those who destroy the earth" (Rev 11:18). The answer is Christ\'s return — the final judgment that ends the cycle of empire\'s violence. Habakkuk\'s question finds its answer not in his own era but in the eschatological coming of the one who judges with equity (Rev 19:11).</p>'
    },
    "2": {
        "1": '<p class="christ-theme">The prophet standing at his watchtower — "I will stand at my watch and station myself on the rampart, and look out to see what he will say to me, and what I will answer concerning my complaint" — is the posture of Christological expectation. The watchman waits for the word from above. This is the posture Hebrews describes for Christian life: "looking to Jesus, the founder and perfecter of our faith" (Heb 12:2). The watching that Habakkuk does at the tower, the disciple does by faith directed toward Christ. Both involve sustained, expectant attention to what comes from above rather than what is visible below.</p>',
        "2": '<p class="christ-theme">YHWH\'s instruction to write the vision plainly on tablets so the herald can run with it — "Write the vision; make it plain on tablets, so he may run who reads it" — is the commissioning of prophetic proclamation. The running herald is the prototype of the apostolic messenger. Paul describes his gospel-proclamation in exactly these terms: "How are they to hear without someone preaching? And how are they to preach unless they are sent? As it is written, \'How beautiful are the feet of those who preach the good news!\'" (Rom 10:14-15, citing Isa 52:7). The vision written for the running herald becomes in Paul\'s framework the gospel entrusted to apostles whose feet carry it to the ends of the earth.</p>',
        "3": '<p class="christ-direct">The vision awaits its appointed time — "it hastens to the end and will not lie. If it seems slow, wait for it; it will surely come; it will not delay." Hebrews 10:37 cites this verse directly in its exhortation to persevering faith: "For yet a little while, and the coming one will come and will not delay." The writer applies the vision\'s coming to the return of Christ — the one whose coming is the fulfillment of all prophetic waiting. The patience Habakkuk must exercise at the watchtower becomes in Hebrews the patience of faith directed toward the parousia. "Wait for it" is the stance of the entire Christian life between the first and second advent.</p>',
        "4": '<p class="christ-direct">The axial verse of the entire book — "Behold, his soul is puffed up; it is not upright within him, but the righteous shall live by his faith (<em>emunah</em>)" — is the most heavily cited OT verse in the NT Epistles. Paul quotes it twice: in Romans 1:17 as the thesis statement of the gospel ("the righteousness of God is revealed from faith for faith, as it is written, \'The righteous shall live by faith\'") and in Galatians 3:11 to establish that justification is not by the law. Hebrews 10:38 also cites it as the charter of enduring faith. The <em>emunah</em> (faithfulness/faith) of Habakkuk 2:4 becomes the <em>pistis</em> (faith) that is the instrument of justification in Christ. The compressed contrast between the proud soul and the faithful soul contains the entire Pauline doctrine of justification by faith.</p>',
        "5": '<p class="christ-theme">The wine being treacherous — the arrogant man not remaining at home, enlarging his desire like Sheol, gathering all nations to himself — is the portrait of insatiable imperial appetite. Christ diagnoses the same soul-condition in his parable of the rich fool: "The land of a rich man produced plentifully, and he thought to himself, \'What shall I do, for I have nowhere to store my crops?\'" (Luke 12:16-17). The soul that is never satisfied, that gathers and stores for itself, is precisely the soul that Habakkuk 2:4 defines as "puffed up" in contrast to the one who lives by faith. Christ offers the alternative: life does not consist in the abundance of possessions (Luke 12:15).</p>',
        "6": '<p class="christ-theme">The first woe — against the one who heaps up what is not his, loading himself with pledges — is the prophetic denunciation of economic exploitation, the creditor who enriches himself through others\' debt. James echoes this woe in exactly these terms: "Come now, you rich, weep and howl for the miseries that are coming upon you... Behold, the wages of the laborers who mowed your fields, which you kept back by fraud, are crying out against you" (Jas 5:1, 4). The woe series in Habakkuk 2 is the OT foundation for the NT\'s consistent economic ethics: the gathered wealth of exploitation will return as judgment on its gatherer.</p>',
        "7": '<p class="christ-theme">Those who bite suddenly rising — "suddenly those who bite you will arise" — describes the reversal of fortunes that justice brings: the exploiters will themselves be exploited. This reversal pattern is the structure of the Magnificat (Luke 1:52-53): "He has brought down the mighty from their thrones and exalted those of humble estate; he has filled the hungry with good things, and the rich he has sent away empty." The reversal Habakkuk announces as prophetic warning, Mary announces as accomplished fact in Christ. The woe against the exploiter is answered in the one who exalts the humble.</p>',
        "8": '<p class="christ-theme">The woe\'s completion — "the remnant of the peoples will plunder you, for the blood of man and violence to the earth, to cities and all who dwell in them" — articulates the principle that violence done to others returns upon its perpetrator. This is the lex talionis universalized into a theological principle of history. Jesus puts the same principle more sharply: "All who take the sword will perish by the sword" (Matt 26:52). But Christ does not merely predict the cycle — he breaks it. His own death absorbs the violence cycle rather than perpetuating it; the one who was violated in his death does not return violence but forgiveness (Luke 23:34).</p>',
        "9": '<p class="christ-theme">The second woe — against the one who gains evil gain for his house, setting his nest on high to escape disaster — is the prophetic denunciation of the security built on exploitation. Jesus names the same false security in the Sermon on the Mount: "Do not lay up for yourselves treasures on earth, where moth and rust destroy and where thieves break in and steal, but lay up for yourselves treasures in heaven" (Matt 6:19-20). The nest set on high (Hab 2:9) is the OT\'s image for the earthly security that cannot ultimately protect. Christ redirects the security drive from the built nest to the Father who feeds the birds and clothes the lilies.</p>',
        "10": '<p class="christ-theme">The shaming of the house — "you have devised shame for your house by cutting off many peoples; you have forfeited your life" — states the ironic reversal: the house built on exploitation is itself shamed. This is the structural wisdom of Proverbs: "The house of the wicked will be destroyed, but the tent of the upright will flourish" (Prov 14:11). Christ builds the household differently: "Unless YHWH builds the house, those who build it labor in vain" (Ps 127:1). The household of the new covenant is built on the one who was shamed on the cross and thereby becomes the cornerstone (1 Pet 2:6-7).</p>',
        "11": '<p class="christ-allusion">The stones crying out from the wall and the beam from the woodwork answering — inorganic creation testifying to injustice — anticipates the cry Jesus promises will not be silenced: "I tell you, if these were silent, the very stones would cry out" (Luke 19:40). When the Pharisees demand the disciples\' silence, Jesus invokes the same testimony of creation. Both the woe in Habakkuk and the Palm Sunday declaration assert that injustice and authentic worship cannot ultimately be suppressed — creation itself will testify. The stones cry out for both justice (Hab 2:11) and praise (Luke 19:40).</p>',
        "12": '<p class="christ-theme">The third woe — against the one who builds a town with blood and founds a city with iniquity — is the prophetic inversion of empire\'s building project. The great cities of the ancient world were built with slave labor and imperial violence. The new city Christ builds needs no such foundation: "I will build my church" (Matt 16:18) — built not on violence but on the confession of Peter and the blood of the one who died for his people. The city of God (Rev 21:2) comes down from heaven rather than being erected by human power and injustice.</p>',
        "13": '<p class="christ-allusion">The declaration that "the nations exhaust themselves for nothing and the peoples weary themselves only for fire" — the futility of empire\'s building project — echoes in Paul\'s contrast between the wood, hay, and stubble burned at the judgment and the gold, silver, and precious stones that endure (1 Cor 3:12-15). The labors of the nations that do not rest on YHWH\'s foundation will be consumed. What is built in Christ endures — "For no one can lay a foundation other than that which is laid, which is Jesus Christ" (1 Cor 3:11).</p>',
        "14": '<p class="christ-allusion">The great promise — "For the earth will be filled with the knowledge of the glory of YHWH as the waters cover the sea" — is the eschatological horizon toward which the entire Habakkuk oracle points. Revelation 21:23 describes its fulfillment in the new creation: "the city has no need of sun or moon to shine on it, for the glory of God gives it light, and its lamp is the Lamb." The glory that Habakkuk promises will fill the earth as waters cover the sea is the glory of the Lamb. Paul also moves toward this horizon: God\'s plan to fill all things in Christ (Eph 1:10, 23) is the NT form of this cosmic glory-filling.</p>',
        "15": '<p class="christ-theme">The fourth woe — against the one who makes his neighbor drink, pouring out your wrath and making them drunk to gaze at their nakedness — is the prophetic denunciation of exploitation through intoxication and shame. The poisoned cup given to the nations is the OT form of the judgment cup Paul identifies as the cup of demons (1 Cor 10:21) — the rival cup to the cup of the Lord. Christ takes the cup of God\'s wrath himself (Matt 26:39, "let this cup pass from me") so that those who drink his cup receive blessing rather than the poison of exploitation.</p>',
        "16": '<p class="christ-type">The cup of YHWH\'s right hand being turned against the one who gave it — "you will be filled with shame instead of glory" — enacts the reversal that the cross effects. The shame that was directed at others returns to the shamers. Christ himself "despised the shame" of the cross (Heb 12:2) and was vindicated in glory. The shame-glory reversal of Habakkuk 2:16 is enacted at Calvary in reverse: Christ takes the shame that belonged to others so that they receive the glory that belonged to him (2 Cor 8:9).</p>',
        "17": '<p class="christ-theme">The violence done to Lebanon and the destruction of its animals — the ecological dimension of imperial violence — coming back on the perpetrator expands the scope of justice to include the non-human creation. Paul announces the same cosmic scope: "the creation was subjected to futility... the whole creation has been groaning together in the pains of childbirth" (Rom 8:20, 22). The redemption Christ brings is not merely individual but cosmic — "the creation itself will be set free from its bondage to corruption and obtain the freedom of the glory of the children of God" (Rom 8:21). The violence done to Lebanon anticipates the groaning creation that awaits the revealing of the sons of God.</p>',
        "18": '<p class="christ-theme">The futility of carved images — "What profit is an idol when its maker has shaped it?" — is the OT\'s consistent polemic against idolatry that Paul universalizes in Romans 1:23. The idol that cannot speak, cannot profit, cannot save is the theological foil against which the living God and his gospel are defined. Christ\'s resurrection is the definitive anti-idol statement: "He is not here, for he has risen" (Matt 28:6). The living one who was dead and is now alive forever (Rev 1:18) cannot be reduced to what the human hand makes or what the human imagination worships.</p>',
        "19": '<p class="christ-theme">The fifth woe — "Woe to him who says to a wooden thing, \'Awake\'; to a silent stone, \'Arise!\'" — reaches its limit at the silence of stone and wood. The same command — "Awake!" and "Arise!" — is what God issues to his Son at the resurrection. Paul cites a hymn fragment in Ephesians 5:14: "Awake, O sleeper, and arise from the dead, and Christ will shine on you." What the idol cannot do — awake, arise — Christ does. The resurrection is the anti-idol event: the one who was laid in a stone tomb, sealed with a stone, rose from death (Matt 28:2). Stone and wood cannot awake; Christ did.</p>',
        "20": '<p class="christ-direct">The climax of the woe series: "But YHWH is in his holy temple; let all the earth keep silence before him." The silence of all the earth before YHWH in his temple is the opposite of the idol who cannot speak. Hebrews 4:16 describes Christian access to this holy presence through Christ: "let us then with confidence draw near to the throne of grace, that we may receive mercy and find grace." The silence Habakkuk commands before YHWH in his temple becomes in Hebrews the confident approach to the throne — not despite YHWH\'s holiness but through the high priest who has passed through the heavens (Heb 4:14). Revelation 8:1 enacts the silence: "there was silence in heaven for about half an hour" before the judgments proceed.</p>'
    },
    "3": {
        "1": '<p class="christ-theme">The prayer of Habakkuk the prophet "according to Shigionoth" — a musical designation suggesting wild, passionate singing — frames the theophanic hymn as liturgical prayer. The prayer takes the form of petition arising from distress. Hebrews 5:7 describes Christ\'s own prayer in Gethsemane in similar terms: "In the days of his flesh, Jesus offered up prayers and supplications, with loud cries and tears, to him who was able to save him from death, and he was heard because of his reverence." The pattern of anguished prayer addressed to the God who can save is the pattern both Habakkuk and Christ model — the one as prophet, the other as the Son who inhabits the pattern to its fullest depth.</p>',
        "2": '<p class="christ-allusion">The petition — "O YHWH, I have heard the report of you, and your work, O YHWH, do I fear. In the midst of the years revive it; in the midst of the years make it known; in wrath remember mercy" — is a prayer for the renewal of YHWH\'s saving work. Paul applies the language of divine renewal to resurrection: "[God] who raised the Lord Jesus will raise us also with Jesus and bring us with you into his presence" (2 Cor 4:14). The "reviving" Habakkuk prays for — the re-enactment of YHWH\'s great acts of deliverance — is accomplished in Christ\'s resurrection, the definitive revival of the works of YHWH in the midst of history.</p>',
        "3": '<p class="christ-allusion">The theophanic vision begins: "God came from Teman, and the Holy One from Mount Paran. His splendor covered the heavens, and the earth was full of his praise." This vision of divine glory coming from the south (Teman = Edom/Sinai) — YHWH marching from the wilderness — is the OT prototype for the incarnation. John 1:14 announces the fulfillment: "the Word became flesh and dwelt among us, and we have seen his glory, glory as of the only Son from the Father." The glory that covered the heavens in Habakkuk\'s vision was concentrated in the person of the one who came not from Teman but from the Father, not with fire and earthquake but with grace and truth.</p>',
        "4": '<p class="christ-allusion">The brightness "like the sunlight" from YHWH\'s hand, with "rays flashing from his hand; and there he veiled his power" — the theophanic light hidden within matter — is the OT prototype for the transfiguration. On the Mount of Transfiguration, "his face shone like the sun, and his clothes became white as light" (Matt 17:2). The veiled power of Habakkuk\'s theophany is unveiled briefly on the mountain and will be fully unveiled at the return: "He will appear a second time... to save those who are eagerly waiting for him" (Heb 9:28). The rays that flash from YHWH\'s hand in Habakkuk\'s vision are the rays that will illuminate the new creation (Rev 22:5).</p>',
        "5": '<p class="christ-type">Pestilence going before YHWH and plague following his steps — the accompaniments of the divine warrior march — describe the total power of YHWH over sickness and death. Christ\'s healing ministry is the direct enactment of this warrior\'s power in mercy rather than judgment. He who could have brought pestilence instead drove it away: "he cast out the spirits with a word and healed all who were sick" (Matt 8:16). The divine power over pestilence and plague that Habakkuk describes as attendants of divine wrath, Jesus deploys as agents of divine compassion — healing, not afflicting, as the sign of the kingdom\'s arrival.</p>',
        "6": '<p class="christ-allusion">YHWH standing and measuring the earth, making nations tremble, causing the eternal mountains to scatter — the cosmic upheaval of theophany — anticipates the cosmic transformation that Christ\'s resurrection initiates. Peter describes the same shaking: "the heavens will pass away with a roar, and the heavenly bodies will be burned up and dissolved" (2 Pet 3:10). Hebrews 12:26-27 cites Haggai\'s parallel ("once more I will shake not only the earth but also the heavens") and interprets it as the removal of what is shakeable so what cannot be shaken may remain. The eternal mountains that scatter before YHWH are the unstable certainties of the old world; what remains is the unshakeable kingdom.</p>',
        "7": '<p class="christ-theme">The tents of Cushan and the curtains of Midian in affliction — foreign nations undone by the advance of YHWH — describe the universal scope of divine sovereignty over the nations. Acts 17:26 carries this into Paul\'s Athens speech: God "made from one man every nation of mankind to live on all the face of the earth, having determined allotted periods and the boundaries of their dwelling place." The God who shook the tents of Cushan in Habakkuk\'s vision is the same God who governs the histories of all nations in Paul\'s proclamation — and who commands all people everywhere to repent (Acts 17:30).</p>',
        "8": '<p class="christ-theme">The rhetorical question — "Was your wrath against the rivers, O YHWH? Was your anger against the rivers, or your indignation against the sea, when you rode on your horses, on your chariot of salvation?" — is the Exodus memory deployed as confidence for the present. The chariot of salvation (<em>merkevot yeshuatecha</em>) is YHWH\'s redemptive vehicle in history. Christ himself is identified as YHWH\'s act of salvation: "She will bear a son, and you shall call his name Jesus (<em>Yeshua</em>), for he will save his people from their sins" (Matt 1:21). The chariot of salvation that Habakkuk invokes in prayer finds its final rider in the one named for the salvation he brings.</p>',
        "9": '<p class="christ-allusion">The stripping bare of the bow, the oaths sworn to the tribes — "you split the earth with rivers" — continues the Exodus-march imagery, now focusing on the covenant oath behind YHWH\'s warfare. The bow stripped bare and ready is the warrior\'s preparation; the rivers split open recall the Red Sea. Hebrews 6:13-18 grounds Christian hope in the same sworn oath: "when God made a promise to Abraham, since he had no one greater by whom to swear, he swore by himself." The covenant oath behind Habakkuk\'s confidence is the same oath that grounds Hebrews\'s assurance — an oath sworn by the one who cannot lie and confirmed in Christ (2 Cor 1:20).</p>',
        "10": '<p class="christ-allusion">The mountains seeing YHWH and writhing, the water overflowing, the deep giving forth its voice — the cosmic response to the divine march — is the OT template for the cosmic upheaval that attends the crucifixion and resurrection. At the cross: "the earth shook, and the rocks were split" (Matt 27:51). At the resurrection: "a great earthquake" and the angel (Matt 28:2). The mountains that writhe at YHWH\'s approach in Habakkuk\'s theophany writhe at the presence of the one who is YHWH incarnate. Creation recognizes its Creator.</p>',
        "11": '<p class="christ-allusion">The sun and moon standing still — "the sun and moon stood still in their place at the light of your arrows as they sped, at the flash of your glittering spear" — recalls Joshua\'s long day (Josh 10:12-14) and points forward to the darkness at the crucifixion: "there was darkness over all the land from the sixth hour to the ninth hour" (Matt 27:45). Creation marks the decisive moments of YHWH\'s redemptive action by its own suspension. Joshua\'s sun-standing and Habakkuk\'s theophanic imagery find their NT correspondence in the midday darkness — creation\'s witness to the death of its Creator.</p>',
        "12": '<p class="christ-theme">YHWH marching through the earth in fury, threshing the nations in anger — the divine warrior bringing judgment — is the imagery Revelation applies to Christ\'s return: "he treads the winepress of the fury of the wrath of God the Almighty" (Rev 19:15). The God who marched in fury against Egypt and Babylon marches again in the final judgment. But Christ\'s first coming is the opposite: not to judge the world but to save it (John 3:17). The divine warrior who threshes the nations in anger at the return first came as the lamb who takes away the world\'s sin (John 1:29). Same person, different missions — first advent to save, second to judge.</p>',
        "13": '<p class="christ-direct">The declaration — "You went out for the salvation of your people, for the salvation of your anointed (<em>Meshiach</em>). You crushed the head of the house of the wicked, laying him bare from thigh to neck" — names YHWH\'s salvific purpose explicitly as going out for the salvation of his <em>Mashiach</em>. Paul announces this fulfillment: Christ "gave himself for us to redeem us from all lawlessness and to purify for himself a people for his own possession" (Titus 2:14). And Peter: "you are a chosen race, a royal priesthood, a holy nation, a people for his own possession" (1 Pet 2:9). The going-out for the salvation of YHWH\'s people is the mission the incarnation enacts — the Son sent from the Father to save the people the Father has given him (John 17:6).</p>',
        "14": '<p class="christ-allusion">YHWH piercing the head of the enemy with his own arrows — "you pierced with his own arrows the heads of his warriors, who came like a whirlwind to scatter me" — is the divine warfare pattern of defeat-by-own-weapons. This is the logic of Christus Victor: "Since therefore the children share in flesh and blood, he himself likewise partook of the same things, that through death he might destroy the one who has the power of death, that is, the devil" (Heb 2:14). The enemy\'s weapon — death — becomes the instrument of the enemy\'s defeat. Christ is pierced (John 19:34) to pierce the head of the one who had the power of death. The enemy\'s weapon turned against him.</p>',
        "15": '<p class="christ-allusion">YHWH treading the sea with his horses, "stirring the great waters" — the march through the divided sea in the Exodus — is the prototype for Jesus walking on the water (Matt 14:25-26). The disciples see Jesus coming on the sea and are terrified; he says "Take heart; it is I" — the Exodus God\'s self-disclosure formula (ego eimi). The one who walked his horses through the sea in Habakkuk\'s vision walks on it himself in the Gospels. The theophanic rider becomes the incarnate walker — YHWH\'s sea-mastery concentrated in the person of the one the disciples worship as they cry "Truly you are the Son of God" (Matt 14:33).</p>',
        "16": '<p class="christ-theme">The prophet\'s response to the vision — "I hear, and my body trembles; my lips quiver at the sound; rottenness enters into my bones; my legs tremble beneath me" — is the bodily experience of divine encounter. John\'s response to the vision of the risen Christ is identical: "When I saw him, I fell at his feet as though dead" (Rev 1:17). The prostration before the divine presence that Habakkuk describes is the response to the same reality — the holiness of YHWH — that John experiences before the risen Lord. Both are lifted up by grace: Habakkuk to wait quietly for the day of trouble, John by the word "Fear not."</p>',
        "17": '<p class="christ-allusion">The great confession of destitution — "Though the fig tree should not blossom, nor fruit be on the vines, the produce of the olive fail and the fields yield no food, the flock be cut off from the fold and there be no herd in the stalls" — catalogs total material loss. Paul makes the same catalog irrelevant by the same logic: "I have learned, in whatever situation I am, to be content. I know how to be brought low, and I know how to abound... I can do all things through him who strengthens me" (Phil 4:11-13). The contentment Habakkuk moves toward by faith, Paul has been taught through experience — because of the one who is the source of all sufficiency. Both the prophet and the apostle arrive at the same place: the material world stripped away, yet God remaining as the ground of joy.</p>',
        "18": '<p class="christ-direct">The declaration — "yet I will rejoice in YHWH; I will take joy in the God of my salvation" — is the concentrated statement of faith that transcends circumstances. Paul echoes it explicitly: "Rejoice in the Lord always; again I will say, rejoice" (Phil 4:4). The "yet" of Habakkuk 3:18 is the pivot-word of NT faith — the turn from despair at circumstances to joy in the unchanging God. The "God of my salvation" (<em>Elohei yishi</em>) is, for the NT, identified as Jesus: Yeshua = salvation = "the Lord who is my salvation." Habakkuk\'s doxological pivot to the God of salvation finds its object in the named one who is that salvation.</p>',
        "19": '<p class="christ-allusion">The closing verse — "YHWH, the Lord, is my strength; he makes my feet like the deer\'s; he makes me tread on my high places" — is the OT\'s declaration of divine empowerment for the journey ahead. Paul appropriates the same source: "I can do all things through him who strengthens me" (Phil 4:13). Ephesians 6:10: "be strong in the Lord and in the strength of his might." The strength that Habakkuk receives from YHWH when everything material has been stripped away is the strength Paul locates in the risen Lord. The deer\'s feet on high places — sure-footed in difficult terrain — is the picture of Christian life empowered by the one who has already conquered the difficult terrain of death itself.</p>'
    }
}

def main():
    existing = load_comm('mkt-christ', 'habakkuk')
    merge_comm(existing, HABAKKUK)
    save_comm('mkt-christ', 'habakkuk', existing)
    print('Habakkuk 1-3 mkt-christ written.')

if __name__ == '__main__':
    main()
